effect.shader:
void main() {
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    vec2 st = acLayerNorm.st;

    float a = angle * 0.0174533;
    st -= 0.5;
    st *= mat2(
        cos(a), -sin(a),
        sin(a), cos(a)
    );
    st += 0.5;

    float x = st.x;

    float y;
    float t;

    y = sin(x * frequency);
    t = 0.01*(-phase*130.0);
    y += sin(x*frequency*2.1 + t)*4.5;
    y += sin(x*frequency*1.72 + t*1.121)*4.0;
    y += sin(x*frequency*2.221 + t*0.437)*5.0;
    y += sin(x*frequency*3.1122+ t*4.269)*2.5;
    y *= amplitude*0.03;
    y += 0.5 + offset;

    float y1 = y;

    y = sin(x * frequency);
    t = 0.01*(-phase*130.0)+width;
    y += sin(x*frequency*2.1 + t)*4.5;
    y += sin(x*frequency*1.72 + t*1.121)*4.0;
    y += sin(x*frequency*2.221 + t*0.437)*5.0;
    y += sin(x*frequency*3.1122+ t*4.269)*2.5;
    y *= amplitude*0.03;
    y += 0.5 + offset;

    float y2 = y;

    //float p = = st.y > min(y1,y2) && st.y < max(y1,y2) ? color : vec4(0.);

    float lowy = min(y1,y2);
    float highy = max(y1,y2);

    //float b = smoothing*(highy-lowy)/2.;
    float b = smoothing/20.;

    //float p = st.y > lowy && st.y < highy ? 1.0 : 0.0;

    float p = min(smoothstep(lowy-b/2.,lowy+b/2.,st.y), 1.-smoothstep(highy-b/2.,highy+b/2.,st.y));

    vec4 mixedColor = mix(color,tintColor,smoothstep(y1,y2,st.y)*tint);

    vec4 c = mixedColor * p;
    if( punchout ) {
        gl_FragColor = texColor * (1.0-p);
    } else {
        c *= texColor.a;
        gl_FragColor = c + (texColor*(1.0-c.a));
    }
}
